sql:
SELECT total_flying_hours 
FROM pilots 
ORDER BY total_flying_hours DESC;

SELECT flight_plan_id
FROM flights
WHERE flight_status = 'pending';

SELECT flight_number
FROM flights
ORDER BY flight_number ASC;

SELECT pilot_name
FROM pilots
WHERE pilot_id = 1;

SELECT p.pilot_name
FROM pilots p
INNER JOIN users u ON p.pilot_id = u.user_id;

SELECT users.user_name, pilots.pilot_name, pilots.pilot_rank
FROM users
INNER JOIN pilots ON users.user_id = pilots.pilot_id;

SELECT DISTINCT flight_number
FROM flights
WHERE flight_status = 'On Time';

SELECT flight_number 
FROM flights
WHERE pilot_id IN (
    SELECT pilot_id 
    FROM pilots 
    WHERE total_flying_hours = (
        SELECT MAX(total_flying_hours) 
        FROM pilots
    )
);

SELECT pilot_name
FROM pilots
WHERE total_flying_hours > (SELECT AVG(total_flying_hours) FROM pilots);

SELECT pilot_name 
FROM pilots
WHERE total_flying_hours = (SELECT MAX(total_flying_hours) FROM pilots);

SELECT pilot_rank, COUNT(*) AS NumberOfPilots
FROM pilots
GROUP BY pilot_rank;

SELECT pilots.pilot_name, access_logs.access_reason
FROM pilots
INNER JOIN access_logs ON pilots.pilot_id = access_logs.user_id;
